rollback.sql:
DELETE FROM public.request_task_type_action_type
WHERE request_task_type_id = (SELECT rtt.id FROM request_task_type rtt WHERE rtt.code = 'VERIFICATION_BODY_NO_LONGER_AVAILABLE_SYSTEM_NOTIFICATION')
AND request_task_action_type_id = (SELECT rtat.id FROM request_task_action_type rtat WHERE rtat.code = 'SYSTEM_MESSAGE_DISMISS');

DELETE FROM public.request_task_type_action_type
WHERE request_task_type_id = (SELECT rtt.id FROM request_task_type rtt WHERE rtt.code = 'NEW_VERIFICATION_BODY_SYSTEM_NOTIFICATION')
AND request_task_action_type_id = (SELECT rtat.id FROM request_task_action_type rtat WHERE rtat.code = 'SYSTEM_MESSAGE_DISMISS');

